+/// Apply Laplacian matrix to a vector in millionths.
+fn apply_laplacian_millionths(laplacian: &LaplacianMatrix, v: &[i64]) -> Vec<i64> {
+    let n = laplacian.dim;
+    let mut out = vec![0i64; n];
+    #[allow(clippy::needless_range_loop)]
+    for i in 0..n {
